import sys

def shortest_palindrome(s):
    n = len(s)
    if n == 0:
        return ""

    # Find the longest palindromic prefix
    max_len = 0
    for i in range(n):
        if s[:n-i] == s[:n-i][::-1]:
            max_len = n - i
            break

    # Add the reverse of the remaining suffix to the end
    return s + s[:max_len-1][::-1]

def solve():
    s = sys.stdin.read().strip()
    print(shortest_palindrome(s))

if __name__ == "__main__":
    solve()
